const businesses = $input.all();
const results = [];
for (const biz of businesses) {
  if (biz.json.name === '_template') continue;
  results.push({ json: { businessId: biz.json.name, businessPath: 'memory-bank/businesses/' + biz.json.name } });
}
return results;

const businessPath = $('Filter Active Businesses').first().json.businessPath;
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
const yesterdayStr = yesterday.toISOString().split('T')[0];
const lastMonday = new Date(now);
const dayOfWeek = lastMonday.getDay();
const daysToMonday = dayOfWeek === 0 ? 6 : (dayOfWeek === 1 ? 7 : dayOfWeek - 1);
lastMonday.setDate(lastMonday.getDate() - daysToMonday);
const lastMondayStr = lastMonday.toISOString().split('T')[0];
const lastTuesday = new Date(lastMonday);
lastTuesday.setDate(lastTuesday.getDate() + 1);
const lastTuesdayStr = lastTuesday.toISOString().split('T')[0];
return [{ json: { businessPath, financeReportPath: businessPath + '/reports/finance-' + yesterdayStr + '.md', contentReportPath: businessPath + '/reports/content-' + lastMondayStr + '.md', marketingReportPath: businessPath + '/reports/marketing-' + lastMondayStr + '.md', productReportPath: businessPath + '/reports/product-' + lastTuesdayStr + '.md', yesterdayDate: yesterdayStr, lastMondayDate: lastMondayStr, lastTuesdayDate: lastTuesdayStr } }];

const businessId = $('Filter Active Businesses').first().json.businessId;
const businessPath = $('Filter Active Businesses').first().json.businessPath;
const dates = $('Compute Report Dates').first().json;

const state = $('Read State').first().json.content || '';
const strategy = $('Read Strategy').first().json.content || '';
const plan = $('Read Weekly Plan').first().json.content || '';
const stateSha = $('Read State').first().json.sha || '';

const financeNode = $('Read Finance Report').first();
const contentNode = $('Read Content Report').first();
const marketingNode = $('Read Marketing Report').first();
const productNode = $('Read Product Report').first();

const financeReport = (financeNode && !financeNode.json.error) ? (financeNode.json.content || '') : '[No finance report available]';
const contentReport = (contentNode && !contentNode.json.error) ? (contentNode.json.content || '') : '[No content report available]';
const marketingReport = (marketingNode && !marketingNode.json.error) ? (marketingNode.json.content || '') : '[No marketing report available]';
const productReport = (productNode && !productNode.json.error) ? (productNode.json.content || '') : '[No product report available]';

// Parse system_context rows into a map
function parseSupabaseArray(nodeName) {
  try {
    const first = $(nodeName).first().json;
    return Array.isArray(first) ? first : [first];
  } catch (e) { return []; }
}

const contextRows = parseSupabaseArray('Read System Context');
const contextMap = {};
for (const row of contextRows) {
  if (row.context_key) contextMap[row.context_key] = row.context_value;
}

const configRows = parseSupabaseArray('Read System Config');
const configMap = {};
for (const row of configRows) {
  if (row.config_key) configMap[row.config_key] = row.config_value;
}

const authorityRows = parseSupabaseArray('Read CEO Authority');
const authority = (authorityRows[0] && authorityRows[0].config_value) ? authorityRows[0].config_value : { requires_approval: ['everything'] };

const today = new Date().toISOString().split('T')[0];

const configSection = Object.entries(configMap).map(function(entry) {
  return '### ' + entry[0] + '
' + JSON.stringify(entry[1], null, 2);
}).join('

');

const approvalList = (authority.requires_approval || []).map(function(a) { return '- ' + a; }).join('
');

const prompt = 'Today is ' + today + '. You are the CEO Agent for The Forge, reviewing business: ' + businessId + '.

You have full visibility into all systems and the authority to issue directives.

# SECTION 1: LIVE METRICS (from system_context)

## Pipeline Summary
' + JSON.stringify(contextMap.pipeline_summary || {}, null, 2) + '

## Revenue Summary
' + JSON.stringify(contextMap.revenue_summary || {}, null, 2) + '

## Traffic Summary
' + JSON.stringify(contextMap.traffic_summary || {}, null, 2) + '

## Content Summary
' + JSON.stringify(contextMap.content_summary || {}, null, 2) + '

## Email Outreach Summary
' + JSON.stringify(contextMap.email_summary || {}, null, 2) + '

## Voice Call Summary
' + JSON.stringify(contextMap.call_summary || {}, null, 2) + '

## Keyword/SEO Summary
' + JSON.stringify(contextMap.keyword_summary || {}, null, 2) + '

## Budget Summary
' + JSON.stringify(contextMap.budget_summary || {}, null, 2) + '

## Pending Opportunities
' + JSON.stringify(contextMap.opportunities_summary || {}, null, 2) + '

## Recent Activity
' + JSON.stringify(contextMap.activity_summary || {}, null, 2) + '

# SECTION 2: CURRENT CONFIGURATION (system_config)
These are the settings that control all workflows. You can issue actions to change any of these.

' + configSection + '

# SECTION 3: YOUR AUTHORITY

' + JSON.stringify(authority, null, 2) + '

You CAN do these without approval:
- Activate/deactivate cold email, AI calling, content, lead gen, SEO monitoring
- Expand regions for lead gen
- Scale email daily limits
- Activate paid ads (up to max_daily_ad_spend)
- Launch a new business

You NEED human approval for:
' + approvalList + '

# SECTION 4: STATE & STRATEGY (from GitHub)

## Current State
' + state + '

## Strategy
' + strategy + '

## Current Weekly Plan
' + plan + '

# SECTION 5: AGENT REPORTS

### Finance Report (' + dates.yesterdayDate + ')
' + financeReport + '

### Content Report (' + dates.lastMondayDate + ')
' + contentReport + '

### Marketing Report (' + dates.lastMondayDate + ')
' + marketingReport + '

### Product Report (' + dates.lastTuesdayDate + ')
' + productReport + '

# YOUR TASK

Perform your daily CEO review:

1. **Situation Assessment**: What is the current state of the business? Flag blockers, risks, or anomalies in the metrics.
2. **Metrics Analysis**: Review pipeline, traffic, revenue, email, calling, content, and budget data. Identify trends (improving, declining, stagnant).
3. **Agent Performance**: Review each agent report. Are they executing? Any gaps?
4. **Strategic Decisions**: Based on all data, decide:
   - Should any channels be activated or deactivated?
   - Should email/calling limits be adjusted?
   - Should regions be expanded?
   - Are there opportunities worth approving?
   - Does pricing need review (flag for approval)?
   - Any budget concerns?
5. **Directives**: Issue specific directives to each agent team.
6. **Priority Update**: Update priorities if needed.

Generate your daily CEO report in structured markdown.

# OUTPUT FORMAT

After your report, include TWO special sections:

## 1. State Update
Include an updated state.md reflecting any changes:

===STATE_UPDATE_START===
(Full updated state.md content here, in markdown)
===STATE_UPDATE_END===

## 2. Actions
If you want to change any system_config values or trigger any actions, output them here.
Each action is a JSON object. Only include actions you actually want to take.

===ACTIONS===
[
  {
    "action": "update_config",
    "business_id": "bayflow",
    "config_key": "cold_email",
    "config_value": { "daily_limit": 50, "sending_domains": ["trybayflow.com"], "active": true }
  },
  {
    "action": "notify_human",
    "message": "Requesting approval to increase ad spend to $100/day",
    "priority": "high"
  },
  {
    "action": "approve_opportunity",
    "opportunity_id": "uuid-here"
  }
]
===END_ACTIONS===

If no actions needed, output:
===ACTIONS===
[]
===END_ACTIONS===';

return [{ json: { businessId, businessPath, stateSha, prompt } }];

const llmOutput = $('CEO LLM Chain').first().json.text || '';
const businessId = $('Merge All Context').first().json.businessId;
const businessPath = $('Merge All Context').first().json.businessPath;
const stateSha = $('Merge All Context').first().json.stateSha;

// Extract state update
var stateUpdate = '';
const stateStart = '===STATE_UPDATE_START===';
const stateEnd = '===STATE_UPDATE_END===';
const startIdx = llmOutput.indexOf(stateStart);
const endIdx = llmOutput.indexOf(stateEnd);
if (startIdx !== -1 && endIdx !== -1) {
  stateUpdate = llmOutput.substring(startIdx + stateStart.length, endIdx).trim();
}

// Extract actions
var actions = [];
const actionsStart = '===ACTIONS===';
const actionsEnd = '===END_ACTIONS===';
const aStartIdx = llmOutput.indexOf(actionsStart);
const aEndIdx = llmOutput.indexOf(actionsEnd);
if (aStartIdx !== -1 && aEndIdx !== -1) {
  const actionsRaw = llmOutput.substring(aStartIdx + actionsStart.length, aEndIdx).trim();
  try { actions = JSON.parse(actionsRaw); } catch (e) { actions = []; }
}

// CEO report is everything before state update marker
var ceoReport = llmOutput;
if (startIdx !== -1) {
  ceoReport = llmOutput.substring(0, startIdx).trim();
}

return [{ json: { businessId, businessPath, stateSha, ceoReport, stateUpdate, hasStateUpdate: stateUpdate.length > 0, actions, hasActions: actions.length > 0 } }];

const parsed = $('Parse CEO Output').first().json;
const actions = parsed.actions || [];
if (actions.length === 0) {
  return [{ json: { skip: true, message: 'No actions to execute', configUpdates: [], notifications: [], approvals: [], other: [], totalActions: 0 } }];
}
var configUpdates = actions.filter(function(a) { return a.action === 'update_config'; });
var notifications = actions.filter(function(a) { return a.action === 'notify_human'; });
var approvals = actions.filter(function(a) { return a.action === 'approve_opportunity'; });
var other = actions.filter(function(a) { return ['update_config','notify_human','approve_opportunity'].indexOf(a.action) === -1; });
return [{ json: { configUpdates, notifications, approvals, other, totalActions: actions.length, skip: false } }];

const prepared = $('Prepare Actions').first().json;
if (prepared.skip || !prepared.configUpdates || prepared.configUpdates.length === 0) {
  return [{ json: { message: 'No config updates to apply', applied: 0 } }];
}
return prepared.configUpdates.map(function(cu) {
  return { json: { business_id: cu.business_id || 'bayflow', config_key: cu.config_key, config_value: cu.config_value, updated_by: 'ceo_agent' } };
});
